CREATE TABLE search_histories (id BIGINT NOT NULL AUTO_INCREMENT, user_id BIGINT NOT NULL, search_type VARCHAR(30) NOT NULL, crop_mode VARCHAR(30), searched_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY(id), CONSTRAINT fk_history_user FOREIGN KEY(user_id) REFERENCES users(id), INDEX idx_history_user_time(user_id,searched_at));
CREATE TABLE saved_results (id BIGINT NOT NULL AUTO_INCREMENT, user_id BIGINT NOT NULL, catalog_item_id VARCHAR(128) NOT NULL, title VARCHAR(255) NOT NULL, image_url VARCHAR(500) NOT NULL, source_url VARCHAR(500), similarity_score DOUBLE NOT NULL, model_version VARCHAR(255) NOT NULL, metadata_json TEXT NOT NULL, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY(id), CONSTRAINT uk_saved_user_catalog UNIQUE(user_id,catalog_item_id), CONSTRAINT fk_saved_user FOREIGN KEY(user_id) REFERENCES users(id));
